parameters.jsCode:
const nombreProducto = $fromAI('product_name', 'Nombre del producto', 'string');
const productos = $('Consultar Catálogo Productos').all();
const nombreBuscado = nombreProducto.toLowerCase();
const p = productos.find(item => item.json.name?.toLowerCase().includes(nombreBuscado));

if (!p) return `Producto no encontrado.`;

const item = p.json;
let extraInfo = '';
if (item.name.toLowerCase().includes('hamburguesa')) extraInfo = 'OPCIÓN: Pollo Crujiente (+2€ por unidad).';
if (item.name.toLowerCase().includes('cesta')) extraInfo = 'OBLIGATORIO: Elegir salsa (Alioli, Brava, Miel y Mostaza, Ketchup).';

return `VERIFICADO: ${item.name} | Precio: ${item.price}€ | Alérgenos: ${item.allergens || 'Consultar'} | ${extraInfo}`;

